import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import NetInfo from '@react-native-community/netinfo';

const TokenGenerator = () => {
  const [isOffline, setIsOffline] = useState(false);
  const [tokens, setTokens] = useState([]);

  const generateToken = () => {
    return Math.random().toString(36).substr(2, 10);
  };

  const generateOfflineToken = () => {
    if (isOffline) {
      const newToken = generateToken();
      setTokens([...tokens, newToken]);
      Alert.alert('New Token Generated', `Token: ${newToken}`);
    }
  };

  useEffect(() => {
    const unsubscribe = NetInfo.addEventListener(state => {
      setIsOffline(!state.isConnected);
    });

    return () => unsubscribe();
  }, []);

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Offline Status: {isOffline ? 'Offline' : 'Online'}</Text>
      <Button title="Generate Token" onPress={generateOfflineToken} />
      <Text style={{ marginTop: 20 }}>Generated Tokens:</Text>
      {tokens.map((token, index) => (
        <Text key={index}>{token}</Text>
      ))}
    </View>
  );
};

export default TokenGenerator;